const crypto = require('crypto');
const input = $json.body ?? $json;
const headers = $json.headers ?? {};
const timestamp = String(headers['x-telmi-timestamp'] ?? '');
const nonce = String(headers['x-telmi-nonce'] ?? '');
const signature = String(headers['x-telmi-signature'] ?? '');
const secret = $env.N8N_SHARED_SECRET;
const raw = JSON.stringify(input);
const expected = crypto.createHmac('sha256', secret).update(`${timestamp}.${nonce}.${raw}`).digest('hex');
if (!signature || signature.length !== expected.length || !crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected)) || Math.abs(Date.now() - Number(timestamp)) > 300000) throw new Error('Signature Telmi AI Studio invalide');
const steps = ['validate', 'tts', 'images'];
return steps.map(step => ({ json: { jobId: input.jobId, callbackBaseUrl: input.callbackBaseUrl.replace(/\/$/, ''), step } }));

const crypto = require('crypto');
const body = '{}';
const timestamp = String(Date.now());
const nonce = crypto.randomUUID();
const secret = $env.N8N_SHARED_SECRET;
if (!secret || secret.length < 24) throw new Error('N8N_SHARED_SECRET manquant');
const signature = crypto.createHmac('sha256', secret).update(`${timestamp}.${nonce}.${body}`).digest('hex');
return [{ json: { ...$json, body, timestamp, nonce, signature } }];
